    const owner = await signer.getAddress();
    const allowance = await this.getAllowance(tokenAddress, owner, spender);
    const req = typeof requiredAmount === "bigint" ? requiredAmount : BigInt(requiredAmount);
    if (allowance >= req) return { approved: false, allowance };
    const receipt = await this.approveMax(tokenAddress, spender, confirmations);
    const newAllowance = await this.getAllowance(tokenAddress, owner, spender);
